26: func xdpConfigModeToFlag(xdpMode string) link.XDPAttachFlags {
27: 	switch xdpMode {
28: 	case option.XDPModeNative, option.XDPModeLinkDriver, option.XDPModeBestEffort:
29: 		return link.XDPDriverMode
30: 	case option.XDPModeGeneric, option.XDPModeLinkGeneric:
31: 		return link.XDPGenericMode
32: 	}
33: 	return 0
34: }
