36: // These constant values are returned by the kernel when querying the XDP program attach mode.
37: // Important: they differ from constants that are used when attaching an XDP program to a netlink device.
38: const (
39: 	xdpAttachedNone uint32 = iota
40: 	xdpAttachedDriver
41: 	xdpAttachedGeneric
42: )
