44: // xdpAttachedModeToFlag maps the attach mode that is returned in the metadata when
45: // querying netlink devices to the attach flags that were used to configure the
46: // xdp program attachement.
47: func xdpAttachedModeToFlag(mode uint32) link.XDPAttachFlags {
48: 	switch mode {
49: 	case xdpAttachedDriver:
50: 		return link.XDPDriverMode
51: 	case xdpAttachedGeneric:
52: 		return link.XDPGenericMode
53: 	}
54: 	return 0
55: }
