57: // maybeUnloadObsoleteXDPPrograms removes bpf_xdp.o from previously used
58: // devices.
59: //
60: // bpffsBase is typically set to /sys/fs/bpf/cilium, but can be a temp directory
61: // during tests.
62: func (l *loader) maybeUnloadObsoleteXDPPrograms(xdpDevs []string, xdpMode, bpffsBase string) {
63: 	links, err := safenetlink.LinkList()
64: 	if err != nil {
65: 		log.WithError(err).Warn("Failed to list links for XDP unload")
66: 	}
67: 
68: 	for _, link := range links {
69: 		linkxdp := link.Attrs().Xdp
70: 		if linkxdp == nil || !linkxdp.Attached {
71: 			// No XDP program is attached
72: 			continue
73: 		}
74: 		if strings.Contains(link.Attrs().Name, "cilium") {
75: 			// Ignore devices created by cilium-agent
76: 			continue
77: 		}
78: 
79: 		used := false
80: 		for _, xdpDev := range xdpDevs {
81: 			if link.Attrs().Name == xdpDev &&
82: 				xdpAttachedModeToFlag(linkxdp.AttachMode) == xdpConfigModeToFlag(xdpMode) {
83: 				// XDP mode matches; don't unload, otherwise we might introduce
84: 				// intermittent connectivity problems
85: 				used = true
86: 				break
87: 			}
88: 		}
89: 		if !used {
90: 			if err := l.DetachXDP(link.Attrs().Name, bpffsBase, symbolFromHostNetdevXDP); err != nil {
91: 				log.WithError(err).Warn("Failed to detach obsolete XDP program")
92: 			}
93: 		}
94: 	}
95: }
