97: // xdpCompileArgs derives compile arguments for bpf_xdp.c.
98: func xdpCompileArgs(xdpDev string, extraCArgs []string) ([]string, error) {
99: 	link, err := safenetlink.LinkByName(xdpDev)
100: 	if err != nil {
101: 		return nil, err
102: 	}
103: 
104: 	args := []string{
105: 		fmt.Sprintf("-DSECLABEL=%d", identity.ReservedIdentityWorld),
106: 		fmt.Sprintf("-DTHIS_INTERFACE_MAC={.addr=%s}", mac.CArrayString(link.Attrs().HardwareAddr)),
107: 		fmt.Sprintf("-DCALLS_MAP=cilium_calls_xdp_%d", link.Attrs().Index),
108: 	}
109: 	args = append(args, extraCArgs...)
110: 	if option.Config.EnableNodePort {
111: 		args = append(args, []string{
112: 			fmt.Sprintf("-DTHIS_MTU=%d", link.Attrs().MTU),
113: 			fmt.Sprintf("-DNATIVE_DEV_IFINDEX=%d", link.Attrs().Index),
114: 			"-DDISABLE_LOOPBACK_LB",
115: 		}...)
116: 	}
117: 	if option.Config.IsDualStack() {
118: 		args = append(args, fmt.Sprintf("-DSECLABEL_IPV4=%d", identity.ReservedIdentityWorldIPv4))
119: 		args = append(args, fmt.Sprintf("-DSECLABEL_IPV6=%d", identity.ReservedIdentityWorldIPv6))
120: 	} else {
121: 		args = append(args, fmt.Sprintf("-DSECLABEL_IPV4=%d", identity.ReservedIdentityWorld))
122: 		args = append(args, fmt.Sprintf("-DSECLABEL_IPV6=%d", identity.ReservedIdentityWorld))
123: 	}
124: 
125: 	return args, nil
126: }
