24: // attachSKBProgram attaches prog to device using tcx if available and enabled,
25: // or legacy tc as a fallback.
26: func attachSKBProgram(device netlink.Link, prog *ebpf.Program, progName, bpffsDir string, parent uint32, tcxEnabled bool) error {
27: 	if prog == nil {
28: 		return fmt.Errorf("program %s is nil", progName)
29: 	}
30: 
31: 	if tcxEnabled {
32: 		// If the device is a netkit device, we know that netkit links are
33: 		// supported, therefore use netkit instead of tcx. For all others like
34: 		// host devices, rely on tcx.
35: 		if device.Type() == "netkit" {
36: 			if err := upsertNetkitProgram(device, prog, progName, bpffsDir, parent); err != nil {
37: 				return fmt.Errorf("attaching netkit program %s: %w", progName, err)
38: 			}
39: 			return nil
40: 		}
41: 
42: 		// Attach using tcx if available. This is seamless on interfaces with
43: 		// existing tc programs since attaching tcx disables legacy tc evaluation.
44: 		err := upsertTCXProgram(device, prog, progName, bpffsDir, parent)
45: 		if err == nil {
46: 			// Created tcx link, clean up any leftover legacy tc attachments.
47: 			if err := removeTCFilters(device, parent); err != nil {
48: 				log.WithError(err).Warnf("Cleaning up legacy tc after attaching tcx program %s", progName)
49: 			}
50: 			// Don't fall back to legacy tc.
51: 			return nil
52: 		}
53: 		if !errors.Is(err, link.ErrNotSupported) {
54: 			// Unrecoverable error, surface to the caller.
55: 			return fmt.Errorf("attaching tcx program %s: %w", progName, err)
56: 		}
57: 	}
58: 
59: 	// tcx not available or disabled, fall back to legacy tc.
60: 	if err := attachTCProgram(device, prog, progName, parent); err != nil {
61: 		return fmt.Errorf("attaching legacy tc program %s: %w", progName, err)
62: 	}
63: 
64: 	// Legacy tc attached, make sure tcx is detached in case of downgrade.
65: 	// netkit can only be used in combination with tcx, but never legacy tc,
66: 	// hence for netkit detaching here would be irrelevant.
67: 	if err := detachGeneric(bpffsDir, progName, "tcx"); err != nil {
68: 		return fmt.Errorf("tcx cleanup after attaching legacy tc program %s: %w", progName, err)
69: 	}
70: 
71: 	return nil
72: }
