74: func detachGeneric(bpffsDir, progName, what string) error {
75: 	pin := filepath.Join(bpffsDir, progName)
76: 	err := bpf.UnpinLink(pin)
77: 	if err == nil {
78: 		log.Infof("Removed %s link at %s", what, pin)
79: 		return nil
80: 	}
81: 	if errors.Is(err, os.ErrNotExist) {
82: 		return nil
83: 	}
84: 
85: 	// The pinned link exists, something went wrong unpinning it.
86: 	return fmt.Errorf("unpinning %s link: %w", what, err)
87: }
